body.raw:
{
  "model": "{{model}}",
  "max_tokens": 1024,
  "system": "You are a precise assistant. Answer in one sentence.",
  "messages": [
    {
      "role": "user",
      "content": "Explain quantum entanglement."
    }
  ]
}

{
  "model": "{{model}}",
  "max_tokens": 64000,
  "stream": true,
  "messages": [
    {
      "role": "user",
      "content": "Write a short haiku about agents."
    }
  ]
}

{
  "model": "{{model}}",
  "max_tokens": 1024,
  "tools": [
    {
      "name": "get_weather",
      "description": "Get current weather for a city.",
      "input_schema": {
        "type": "object",
        "properties": {
          "location": {
            "type": "string",
            "description": "City and state, e.g. Paris, FR"
          }
        },
        "required": [
          "location"
        ]
      }
    }
  ],
  "messages": [
    {
      "role": "user",
      "content": "What is the weather in Paris?"
    }
  ]
}

{
  "model": "{{model}}",
  "max_tokens": 1024,
  "tools": [
    {
      "name": "get_weather",
      "description": "Get weather.",
      "input_schema": {
        "type": "object",
        "properties": {
          "location": {
            "type": "string"
          }
        },
        "required": [
          "location"
        ]
      }
    }
  ],
  "messages": [
    {
      "role": "user",
      "content": "What is the weather in Paris?"
    },
    {
      "role": "assistant",
      "content": [
        {
          "type": "text",
          "text": "Let me check."
        },
        {
          "type": "tool_use",
          "id": "toolu_REPLACE_ME",
          "name": "get_weather",
          "input": {
            "location": "Paris"
          }
        }
      ]
    },
    {
      "role": "user",
      "content": [
        {
          "type": "tool_result",
          "tool_use_id": "toolu_REPLACE_ME",
          "content": "72F and sunny"
        }
      ]
    }
  ]
}

{
  "model": "{{model}}",
  "max_tokens": 1024,
  "system": [
    {
      "type": "text",
      "text": "You are an expert on Claude. Respond concisely.",
      "cache_control": {
        "type": "ephemeral"
      }
    }
  ],
  "messages": [
    {
      "role": "user",
      "content": "Who built you?"
    }
  ]
}

{
  "model": "{{model}}",
  "max_tokens": 1024,
  "output_config": {
    "format": {
      "type": "json_schema",
      "schema": {
        "type": "object",
        "properties": {
          "name": {
            "type": "string"
          },
          "email": {
            "type": "string"
          },
          "plan": {
            "type": "string"
          }
        },
        "required": [
          "name",
          "email",
          "plan"
        ],
        "additionalProperties": false
      }
    }
  },
  "messages": [
    {
      "role": "user",
      "content": "Extract: Jane Doe <jane@co.com> wants the Enterprise plan."
    }
  ]
}

{
  "name": "Coding Assistant",
  "model": "{{model}}",
  "system": "You are a helpful coding agent.",
  "tools": [
    {
      "type": "agent_toolset_20260401"
    }
  ]
}

{
  "system": "You are an updated coding agent that writes idiomatic Python."
}

{
  "events": [
    {
      "type": "user.message",
      "content": [
        {
          "type": "text",
          "text": "Review the auth module for security issues."
        }
      ]
    }
  ]
}

{
  "events": [
    {
      "type": "user.define_outcome",
      "description": "Build a DCF model for Costco in .xlsx",
      "rubric": {
        "type": "text",
        "content": "Must include 5 years of historical data, terminal value, and sensitivity table."
      },
      "max_iterations": 5
    }
  ]
}

{
  "display_name": "My Custom Skill",
  "description": "What this skill helps Claude do."
}
